INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('503', '<p><strong>Conversation 2</strong><br/>Tour assistant : Ladies and gentleman. . . . (4) . . . before we board for the cruise.<br/>Tourist : Sorry to interrupt, but . . . <strong>(5)</strong> . . . I can''t hear you.<br/>Tour assistant : Certainly. . . . (6) . . . to always have your passport with you or else you won''t be allowed to get on the boat.<br/>Tourist : . . . (7) . . . I don''t have my passport. What should I do ?<br/>Tour assistant : (Sighing) . . . (8) . . .</p><p><strong>5. เลือกคำตอบเพื่อเติมลงในช่องว่าง (5)</strong></p>', '{"A":"can you lower your volume ?","B":"could you please speak a little louder ?","C":"would you like to speak out ?","D":"do you mind making a loud noise ?"}', 'B', '<p><strong>ตอบ 2) could you please speak a little louder ? (คุณกรุณาพูดให้ดังขึ้นอีกหน่อยได้ไหม)</strong></p><p>นักท่องเที่ยวบอกว่าไม่ได้ยิน (I can''t hear you) จึงต้องขอให้ไกด์พูดให้ดังขึ้น</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["บทสนทนา (Conversation)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('504', '<p><strong>Conversation 2</strong><br/>Tour assistant : Ladies and gentleman. . . . (4) . . . before we board for the cruise.<br/>Tourist : Sorry to interrupt, but . . . (5) . . . I can''t hear you.<br/>Tour assistant : Certainly. . . . <strong>(6)</strong> . . . to always have your passport with you or else you won''t be allowed to get on the boat.<br/>Tourist : . . . (7) . . . I don''t have my passport. What should I do ?<br/>Tour assistant : (Sighing) . . . (8) . . .</p><p><strong>6. เลือกคำตอบเพื่อเติมลงในช่องว่าง (6)</strong></p>', '{"A":"Please be sure","B":"Don''t remember","C":"It''s a pleasure","D":"Do you hear me"}', 'A', '<p><strong>ตอบ 1) Please be sure (กรุณาตรวจสอบให้แน่ใจ)</strong></p><p>ไกด์ย้ำเตือนให้แน่ใจว่าต้องพกพาสปอร์ตติดตัวไว้เสมอ (to always have your passport with you)</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["บทสนทนา (Conversation)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('505', '<p><strong>Conversation 2</strong><br/>Tour assistant : Ladies and gentleman. . . . (4) . . . before we board for the cruise.<br/>Tourist : Sorry to interrupt, but . . . (5) . . . I can''t hear you.<br/>Tour assistant : Certainly. . . . (6) . . . to always have your passport with you or else you won''t be allowed to get on the boat.<br/>Tourist : . . . <strong>(7)</strong> . . . I don''t have my passport. What should I do ?<br/>Tour assistant : (Sighing) . . . (8) . . .</p><p><strong>7. เลือกคำตอบเพื่อเติมลงในช่องว่าง (7)</strong></p>', '{"A":"How great !","B":"Truly,","C":"Oh, no!","D":"Hopefully"}', 'C', '<p><strong>ตอบ 3) Oh, no! (โอ้ ไม่นะ)</strong></p><p>นักท่องเที่ยวเพิ่งรู้ตัวว่าไม่มีพาสปอร์ต จึงใช้อุทานเพื่อแสดงความตกใจกับปัญหา</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["บทสนทนา (Conversation)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('506', '<p><strong>Conversation 2</strong><br/>Tour assistant : Ladies and gentleman. . . . (4) . . . before we board for the cruise.<br/>Tourist : Sorry to interrupt, but . . . (5) . . . I can''t hear you.<br/>Tour assistant : Certainly. . . . (6) . . . to always have your passport with you or else you won''t be allowed to get on the boat.<br/>Tourist : . . . (7) . . . I don''t have my passport. What should I do ?<br/>Tour assistant : (Sighing) . . . <strong>(8)</strong> . . .</p><p><strong>8. เลือกคำตอบเพื่อเติมลงในช่องว่าง (8)</strong></p>', '{"A":"You made my day.","B":"Are you serious ?","C":"Is it your mistake ?","D":"I don''t mind."}', 'B', '<p><strong>ตอบ 2) Are you serious ? (คุณพูดจริงไหม)</strong></p><p>ไกด์มีอาการถอนหายใจ (Sighing) และถามด้วยความเหนื่อยใจหรือตกใจว่าคุณพูดจริงหรือเปล่าที่ไม่ได้พกพาสปอร์ตมา ซึ่งเป็นเรื่องสำคัญมากก่อนขึ้นเรือ</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["บทสนทนา (Conversation)"]', '2559');
